SELECT MIN(starttime) AS starttime, MAX(endtime) AS endtime, CAST(TIMEDIFF( STR_TO_DATE(MAX(endtime), '%Y-%m-%d %H:%i:%s'), STR_TO_DATE(MIN(starttime), '%Y-%m-%d %H:%i:%s') ) AS CHAR) AS elapsedtime, CAST(SUM(CASE WHEN error IN ('0.0', '0.00', '0', '0.000') THEN 1 ELSE 0 END) AS CHAR) AS sucessCount, CAST(SUM(CASE WHEN error NOT IN ('0.0', '0.00', '0', '0.000') OR error IS NULL THEN 1 ELSE 0 END) AS CHAR) AS failCount FROM interface_current_report
AND lastruntime >= #{lastruntime,jdbcType=VARCHAR}
